import { useState, MouseEvent } from "react";
import { motion, AnimatePresence } from "motion/react";
import { Maximize2, X, ChevronLeft, ChevronRight } from "lucide-react";

// Real WuBar event photography — embedded directly as data URIs.
// This intentionally bypasses the asset-generation pipeline, since these
// are actual photos, not AI-generated images.
const grapefruitRosemaryImage = "data:image/webp;base64,";
const orchidColadaImage = "data:image/webp;base64,";
const spicedAppleTrioImage = "data:image/webp;base64,";
const gingerWatermelonImage = "data:image/webp;base64,";
const goldTrayServeImage = "data:image/webp;base64,";
const cucumberColadaImage = "data:image/webp;base64,";

interface GalleryProps {
  isLightMode?: boolean;
  heroImage: string;
  barImage: string;
  martiniImage: string;
}

interface GalleryItem {
  id: string;
  src: string;
  title: string;
  category: "Setup" | "Craft" | "Vibe";
  aspect: "tall" | "wide" | "square";
}

export default function Gallery({ heroImage, barImage, martiniImage }: GalleryProps) {
  const [lightboxIndex, setLightboxIndex] = useState<number | null>(null);

  const galleryItems: GalleryItem[] = [
    {
      id: "1",
      src: grapefruitRosemaryImage,
      title: "Grapefruit & rosemary old fashioned, paired with a raspberry mint cooler — rooftop bar service",
      category: "Craft",
      aspect: "wide"
    },
    {
      id: "2",
      src: orchidColadaImage,
      title: "Orchid-topped coladas and mint watermelon coolers, styled for an outdoor reception",
      category: "Craft",
      aspect: "wide"
    },
    {
      id: "3",
      src: spicedAppleTrioImage,
      title: "Spiced apple, citrus, and watermelon serves lined up bar-side in the garden",
      category: "Craft",
      aspect: "tall"
    },
    {
      id: "4",
      src: gingerWatermelonImage,
      title: "Candied ginger & lime serve up front, chili-watermelon margaritas behind — patio setup",
      category: "Craft",
      aspect: "wide"
    },
    {
      id: "5",
      src: goldTrayServeImage,
      title: "Cinnamon spice, raspberry coconut, and charcoal pineapple — our signature tray service",
      category: "Craft",
      aspect: "tall"
    },
    {
      id: "6",
      src: cucumberColadaImage,
      title: "Cucumber cooler, coconut colada, and a chili-rosemary serve at golden hour",
      category: "Craft",
      aspect: "tall"
    }
  ];

  const handlePrev = (e: MouseEvent) => {
    e.stopPropagation();
    if (lightboxIndex === null) return;
    setLightboxIndex((prev) => (prev === 0 ? galleryItems.length - 1 : (prev ?? 0) - 1));
  };

  const handleNext = (e: MouseEvent) => {
    e.stopPropagation();
    if (lightboxIndex === null) return;
    setLightboxIndex((prev) => (prev === galleryItems.length - 1 ? 0 : (prev ?? 0) + 1));
  };

  return (
    <section id="gallery" className="py-12 md:py-16 relative bg-brand-bg">
      <div className="max-w-7xl mx-auto px-6 md:px-12 relative z-10">
        
        {/* Gallery Intro */}
        <div className="text-center max-w-2xl mx-auto mb-20 space-y-4">
          <span className="font-mono text-xs tracking-[0.3em] text-brand-sage font-bold uppercase block">
            VISUAL PORTFOLIO
          </span>
          <h2 className="font-serif text-3xl md:text-5xl font-light tracking-tight text-brand-charcoal">
            The Wu Bar <span className="italic font-normal text-brand-rose">Gallery</span>
          </h2>
          <p className="font-sans text-xs md:text-sm font-light leading-relaxed max-w-lg mx-auto text-brand-charcoal/70">
            An editorial lookbook of our premium setups, artisan garnishes, and real-time event atmosphere across Singapore.
          </p>
        </div>

        {/* Structured Grid Layout */}
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {galleryItems.map((item, idx) => (
            <motion.div
              key={item.id}
              initial={{ opacity: 0, y: 30 }}
              whileInView={{ opacity: 1, y: 0 }}
              viewport={{ once: true }}
              transition={{ duration: 0.6, delay: idx * 0.05 }}
              onClick={() => setLightboxIndex(idx)}
              className="gallery-item relative overflow-hidden rounded-3xl border border-brand-sage/10 cursor-pointer group aspect-[4/3] w-full"
            >
              <img
                src={item.src}
                alt={item.title}
                className="w-full h-full object-cover filter brightness-95 group-hover:brightness-90 transition-all duration-700 group-hover:scale-[1.02]"
                referrerPolicy="no-referrer"
              />
              
              {/* Luxury Cover Overlay on Hover */}
              <div className="absolute inset-0 bg-brand-charcoal/40 opacity-0 group-hover:opacity-100 transition-opacity duration-300 flex flex-col justify-between p-6">
                <div className="flex justify-between items-start">
                  <span className="font-mono text-[9px] tracking-widest font-bold bg-brand-rose text-white py-1 px-3 rounded-full uppercase">
                    {item.category}
                  </span>
                  <div className="p-2 rounded-full bg-white/90 text-brand-sage border border-brand-sage/20">
                    <Maximize2 className="w-3.5 h-3.5" />
                  </div>
                </div>

                <div className="space-y-1 text-left">
                  <h4 className="font-serif text-base text-white leading-snug">
                    {item.title}
                  </h4>
                  <span className="font-mono text-[8px] tracking-widest text-brand-rose uppercase">
                    WU BAR SG • PRESS TO EXPAND
                  </span>
                </div>
              </div>
            </motion.div>
          ))}
        </div>

        {/* Immersive Lightbox Modal */}
        <AnimatePresence>
          {lightboxIndex !== null && (
            <motion.div
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              exit={{ opacity: 0 }}
              className="fixed inset-0 z-50 bg-black/95 flex items-center justify-center p-4 md:p-12"
              onClick={() => setLightboxIndex(null)}
            >
              {/* Top Controls */}
              <div className="absolute top-6 inset-x-6 flex justify-between items-center text-white">
                <span className="font-mono text-[10px] tracking-widest text-brand-rose">
                  {lightboxIndex + 1} / {galleryItems.length} • {galleryItems[lightboxIndex].category.toUpperCase()}
                </span>
                <button
                  onClick={() => setLightboxIndex(null)}
                  className="p-3 bg-white/10 hover:bg-brand-rose hover:text-white rounded-full transition-all text-white border border-white/20 flex items-center gap-1.5 font-mono text-[10px] uppercase font-bold"
                >
                  <X className="w-4 h-4" />
                  <span>Exit</span>
                </button>
              </div>

              {/* Navigation Arrows */}
              <button
                onClick={handlePrev}
                className="absolute left-4 md:left-8 p-4 rounded-full bg-white/10 text-white hover:bg-brand-rose hover:text-white border border-white/20 transition-all"
                title="Previous image"
              >
                <ChevronLeft className="w-6 h-6" />
              </button>

              {/* Main Image View */}
              <motion.div
                key={lightboxIndex}
                initial={{ scale: 0.95 }}
                animate={{ scale: 1 }}
                exit={{ scale: 0.95 }}
                transition={{ duration: 0.3 }}
                className="max-w-4xl max-h-[75vh] relative rounded-2xl overflow-hidden border border-white/10"
                onClick={(e) => e.stopPropagation()}
              >
                <img
                  src={galleryItems[lightboxIndex].src}
                  alt={galleryItems[lightboxIndex].title}
                  className="max-w-full max-h-[75vh] object-contain mx-auto"
                  referrerPolicy="no-referrer"
                />
                
                {/* Image caption tray */}
                <div className="absolute bottom-0 inset-x-0 bg-gradient-to-t from-black/80 to-transparent p-6 text-left space-y-1">
                  <h3 className="font-serif text-lg md:text-xl text-brand-rose font-light">
                    {galleryItems[lightboxIndex].title}
                  </h3>
                  <span className="font-mono text-[8px] tracking-widest text-white/50 uppercase block">
                    WU BAR SG • EVENT PHOTOGRAPHY
                  </span>
                </div>
              </motion.div>

              <button
                onClick={handleNext}
                className="absolute right-4 md:right-8 p-4 rounded-full bg-white/10 text-white hover:bg-brand-rose hover:text-white border border-white/20 transition-all"
                title="Next image"
              >
                <ChevronRight className="w-6 h-6" />
              </button>
            </motion.div>
          )}
        </AnimatePresence>
      </div>
    </section>
  );
}
